using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
        // Preserve the old property name so existing documents are still recognized.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Default id format changed from "EntityType|Key" to just "Key".
        // Preserve the old format so existing documents (e.g. "Blog|1") are still found.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id");
        modelBuilder.Entity<Blog>().UseIdProperty(
            b => "Blog|" + b.Id);

        // Breaking change 3: HasIndex() now throws on Cosmos — indexes are managed
        // via Cosmos DB indexing policy, not EF model configuration. Removed.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

